# Pure RAG: same vector store for every user, no per-user context
def answer(query: str) -> str:
    chunks = vector_store.search(query, top_k=5)
    context = "\n\n".join(c.text for c in chunks)
    return llm.complete(
        system=f"Answer using only this context:\n{context}",
        user=query,
    )

# Feature-driven personalisation: no vector search, structured context only
def personalised_response(user_id: str, query: str) -> str:
    features = feature_store.read(
        entity_id=user_id,
        feature_names=["language", "subscription_tier", "conversation_summary"],
    )
    system = (
        f"You are a helpful assistant.\n"
        f"User language: {features['language']}\n"
        f"Subscription: {features['subscription_tier']}\n"
        f"Prior context: {features['conversation_summary']}"
    )
    return llm.complete(system=system, user=query)

import asyncio

async def personalised_rag(user_id: str, query: str) -> str:
    # Parallelise: feature lookup and vector search are independent
    features_task = asyncio.create_task(
        feature_store.read_async(
            entity_id=user_id,
            feature_names=["language", "subscription_tier", "conversation_summary"],
        )
    )
    chunks_task = asyncio.create_task(
        vector_store.search_async(query, top_k=5)
    )

    features, chunks = await asyncio.gather(features_task, chunks_task)

    knowledge = "\n\n".join(f"[{i+1}] {c.text}" for i, c in enumerate(chunks))

    system = f"""You are a helpful assistant.
User language: {features['language']}
Subscription: {features['subscription_tier']}
Prior context: {features['conversation_summary']}

Relevant knowledge:
{knowledge}

Answer using the knowledge above and the user context."""

    return await llm.complete_async(system=system, user=query)

from dataclasses import dataclass
from typing import Optional
import time

@dataclass
class ContextPipelineHealth:
    feature_store_latency_ms: float
    vector_store_latency_ms: float
    feature_store_hit_rate: float    # fraction of reads that found a value
    vector_store_recall_at_5: float  # offline metric: fraction of gold docs in top-5
    feature_freshness_ok: bool       # no active SLA violations
    vector_index_size: int           # total vectors indexed

    @property
    def is_healthy(self) -> bool:
        return (
            self.feature_store_latency_ms < 5
            and self.vector_store_latency_ms < 80
            and self.feature_store_hit_rate > 0.99
            and self.feature_freshness_ok
        )

    def summary(self) -> str:
        status = "OK" if self.is_healthy else "DEGRADED"
        return (
            f"[{status}] "
            f"FS={self.feature_store_latency_ms:.1f}ms hit={self.feature_store_hit_rate:.3f} "
            f"fresh={self.feature_freshness_ok} | "
            f"VS={self.vector_store_latency_ms:.1f}ms recall@5={self.vector_store_recall_at_5:.3f} "
            f"idx={self.vector_index_size:,}"
        )

DEFAULT_FEATURES = {
    "language": "en",
    "subscription_tier": "free",
    "conversation_summary": "",
}

def read_features_with_fallback(user_id: str) -> dict:
    try:
        features = feature_store.read(
            entity_id=user_id,
            feature_names=list(DEFAULT_FEATURES),
            timeout_ms=10,   # fail fast; do not let a slow store block the request
        )
        # Fill in any missing features with defaults
        return {k: features.get(k) or DEFAULT_FEATURES[k] for k in DEFAULT_FEATURES}
    except Exception as exc:
        # Log and emit metric; degrade gracefully
        logger.warning("feature_store_fallback user=%s err=%s", user_id, exc)
        metrics.increment("feature_store.fallback")
        return DEFAULT_FEATURES.copy()
